async (params, browser) => {
  // Search X
  await browser.open('https://x.com/search')

  // Wait for tweets to appear
  await browser.waitForSelector('article[data-testid=\'tweet\']', 15000)

  // Let more tweets render
  await browser.wait(1500)

  // Scroll to load more tweets
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const tweets = []; const articles = document.querySelectorAll('article[data-testid="tweet"]'); for (let i = 0; i < Math.min(articles.length, 10); i++) { const el = articles[i]; const userNameEl = el.querySelector('[data-testid="User-Name"]'); const tweetTextEl = el.querySelector('[data-testid="tweetText"]'); const timeEl = el.querySelector('time'); const linkEl = el.querySelector('a[href*="/status/"]'); const likeEl = el.querySelector('[data-testid$="like"] span, [data-testid$="unlike"] span'); const retweetEl = el.querySelector('[data-testid$="retweet"] span, [data-testid$="unretweet"] span'); const replyEl = el.querySelector('[data-testid="reply"] span'); tweets.push({ author: userNameEl ? userNameEl.textContent.trim() : 'Unknown', text: tweetTextEl ? tweetTextEl.textContent.trim() : '', time: timeEl ? timeEl.getAttribute('datetime') : '', url: linkEl ? 'https://x.com' + linkEl.getAttribute('href') : '', likes: likeEl ? likeEl.textContent.trim() : '0', retweets: retweetEl ? retweetEl.textContent.trim() : '0', replies: replyEl ? replyEl.textContent.trim() : '0' }); } return { tweet_count: tweets.length, tweets: tweets }`)

  return search_results
}
